// Solution
function calculate<T>(expression: string): number {
    const parsedExpression = esprima.parse(expression);
    const result = parsedExpression.body[0].expression;
    if (result.type === 'BinaryExpression') {
        const left = result.left;
        const right = result.right;
        if (left.type === 'Literal' && right.type === 'Literal') {
            const leftValue = left.value;
            const rightValue = right.value;
            if (typeof leftValue === 'number' && typeof rightValue === 'number') {
                return leftValue + rightValue;
            } else if (typeof leftValue === 'number' && typeof rightValue === 'string') {
                return leftValue + parseFloat(rightValue);
            } else if (typeof leftValue === 'string' && typeof rightValue === 'number') {
                return parseFloat(leftValue) + rightValue;
            } else if (typeof leftValue === 'string' && typeof rightValue === 'string') {
                return parseFloat(leftValue) + parseFloat(rightValue);
            }
        } else if (left.type === 'Literal' && right.type === 'BinaryExpression') {
            const leftValue = left.value;
            const right = right;
            if (typeof leftValue === 'number' && typeof right.left.value === 'number') {
                return leftValue + right.left.value;
            } else if (typeof leftValue === 'number' && typeof right.left.value === 'string') {
                return leftValue + parseFloat(right.left.value);
            } else if (typeof leftValue === 'string' && typeof right.left.value === 'number') {
                return parseFloat(leftValue) + right.left.value;
            } else if (typeof leftValue === 'string' && typeof right.left.value === 'string') {
                return parseFloat(leftValue) + parseFloat(right.left.value);
            }
        } else if (left.type === 'BinaryExpression' && right.type === 'Literal') {
            const rightValue = right.value;
            const left = left;
            if (typeof left.left.value === 'number' && typeof rightValue === 'number') {
                return left.left.value + rightValue;
            } else if (typeof left.left.value === 'number' && typeof rightValue === 'string') {
                return left.left.value + parseFloat(rightValue);
            } else if (typeof left.left.value === 'string' && typeof rightValue === 'number') {
                return parseFloat(left.left.value) + rightValue;
            } else if (typeof left.left.value === 'string' && typeof rightValue === 'string') {
                return parseFloat(left.left.value) + parseFloat(rightValue);
            }
        }
    }
    return 0;
}

